impl Solution { pub fn minimum_cost(m: i32, n: i32, mut h: Vec<i32>, mut v: Vec<i32>) -> i32 { h.sort_unstable_by(|a, b| b.cmp(a)); v.sort_unstable_by(|a, b| b.cmp(a)); let (mut i, mut j, mut black_h_pieces, mut black_v_pieces, mut black_total) = (0, 0, 1, 1, 0); while i < h.len() || j < v.len() { if j == v.len() || (i < h.len() && h[i] > v[j]) { black_total += h[i] * black_v_pieces; black_h_pieces += 1; i += 1; } else { black_total += v[j] * black_h_pieces; black_v_pieces += 1; j += 1; } } black_total } }